var tokenData = {};
var searchData = {};
try { tokenData = $('GOVWIN_CREDENTIALS - Get Token').first().json; } catch(e) {}
try { searchData = $('GOVWIN_CREDENTIALS - Search Opportunities').first().json; } catch(e) {}
var tokenValid = tokenData.access_token && !tokenData.error;
var opportunities = [];
if (tokenValid && searchData) {
  var raw = Array.isArray(searchData) ? searchData : Array.isArray(searchData.opportunities) ? searchData.opportunities : Array.isArray(searchData.results) ? searchData.results : Array.isArray(searchData.items) ? searchData.items : [];
  opportunities = raw.slice(0, 50).map(function(opp, idx) {
    return { id: opp.id || opp.opportunityId || null, title: opp.title || opp.name || 'Unknown', agency: opp.agency || opp.organization || '', value_estimate: opp.valueEstimate || opp.estimatedValue || null, naics: opp.naicsCode || opp.naics || '', posted_date: opp.postedDate || opp.publishedDate || null, response_deadline: opp.responseDeadline || opp.dueDate || null, status: opp.status || 'Active', url: opp.url || ('https://iq.govwin.com/neo/opportunity/' + (opp.id || '')), update_date: opp.updateDate || opp.modifiedDate || new Date().toISOString(), extended_detail: idx < 10, cached_at: new Date().toISOString() };
  });
}
return [{ json: { govwin_status: tokenValid ? 'active' : 'credentials_not_configured', govwin_opportunity_count: opportunities.length, govwin_opportunities: opportunities.slice(0, 10), govwin_all_count: opportunities.length, govwin_note: tokenValid ? null : 'Set GOVWIN_USERNAME/PASSWORD/CLIENT_ID/CLIENT_SECRET in GOVWIN_CREDENTIALS - Get Token node to activate' } }];

const MAX_OPPS = 25;
const TOP_EXTENDED = 5;
const CACHE_TTL_HOURS = 6;
const HOURLY_LIMIT = 500;
return [{ json: { govwin_status: 'PLACEHOLDER - Add GovWin credentials and HTTP Request node', rate_limits: { max_opps: MAX_OPPS, top_extended: TOP_EXTENDED, cache_ttl_hours: CACHE_TTL_HOURS, hourly_limit: HOURLY_LIMIT } }}];

function sumAwards(nodeData) {
  if (!nodeData || (nodeData.error && !nodeData.results)) {
    return { top_n_sum: 0, top_n_count: 0, has_more: false, top_contracts: [], has_data: false };
  }
  var results = nodeData.results || [];
  var total = results.reduce(function(sum, a) { return sum + (parseFloat(a['Award Amount']) || 0); }, 0);
  var hasMore = !!(nodeData.page_metadata && nodeData.page_metadata.hasNext);
  return {
    top_n_sum: total,
    top_n_count: results.length,
    has_more: hasMore,
    has_data: results.length > 0,
    top_contracts: results.slice(0, 5).map(function(a) {
      return {
        recipient: a['Recipient Name'] || 'Unknown',
        amount: parseFloat(a['Award Amount']) || 0,
        description: (a['Description'] || '').substring(0, 120),
        sub_agency: a['Awarding Sub Agency'] || ''
      };
    })
  };
}
function fmt(n) {
  if (!n || n === 0) return '$0';
  if (n >= 1e9) return '$' + (n / 1e9).toFixed(2) + 'B';
  if (n >= 1e6) return '$' + (n / 1e6).toFixed(0) + 'M';
  return '$' + Math.round(n).toLocaleString();
}
var socom   = sumAwards($('Fetch SOCOM Spending').first().json);
var tradoc  = sumAwards($('Fetch TRADOC Spending').first().json);
var peostri = sumAwards($('Fetch PEO STRI Spending').first().json);
var afc     = sumAwards($('Fetch AFC Spending').first().json);
var inscom  = sumAwards($('Fetch INSCOM Spending').first().json);
var cyber   = sumAwards($('Fetch CYBERCOM Spending').first().json);
var dla     = sumAwards($('Fetch DLA Spending').first().json);
var tav1 = $('Tavily - TRADOC Budget').first().json;
var tav2 = $('Tavily - SOCOM Spending').first().json;
var tav3 = $('Tavily - PEO STRI Budget').first().json;

function extractTavily(data, max) {
  max = max || 3;
  var results = data.results || [];
  if (!results.length) return '  No results returned.';
  return results.slice(0, max).map(function(r) {
    return '  TITLE: ' + (r.title || 'N/A') + '\n  URL: ' + (r.url || 'N/A') + '\n  EXCERPT: ' + (r.content || r.snippet || '').substring(0, 400);
  }).join('\n---\n');
}
function agencySection(label, data) {
  var note;
  if (data.has_data) {
    var scope = data.has_more ? 'top ' + data.top_n_count + ' of many' : 'all ' + data.top_n_count;
    note = 'SOURCE: USASpending.gov FY2025 (Oct 2024 - Sep 2025)\n' +
           '  VERIFIED: sum of ' + scope + ' keyword-matched contracts = ' + fmt(data.top_n_sum) + '\n' +
           '  Note: this is NOT total agency obligation — use fy_budget tag accordingly';
  } else {
    note = 'SOURCE: USASpending.gov — ZERO matching contracts returned for these keywords.\n' +
           '  WARNING: All dollar figures for this agency MUST be tagged [ESTIMATED - no verified source].';
  }
  var lines = data.top_contracts.length > 0
    ? '\n  TOP CONTRACTS (by award amount):\n' + data.top_contracts.map(function(c) {
        return '    * ' + c.recipient + ': ' + fmt(c.amount) + ' | ' + c.description.substring(0, 100);
      }).join('\n')
    : '\n  No contract records returned.';
  return '[' + label + ']\n  ' + note + lines;
}
var sections = [
  agencySection('SOCOM (U.S. Special Operations Command)', socom),
  agencySection('TRADOC (Training and Doctrine Command)', tradoc),
  agencySection('PEO STRI (Program Executive Office – Simulation Training & Instrumentation)', peostri),
  agencySection('AFC (Army Futures Command)', afc),
  agencySection('INSCOM (Army Intelligence & Security Command)', inscom),
  agencySection('CYBERCOM (U.S. Cyber Command)', cyber),
  agencySection('DLA (Defense Logistics Agency)', dla)
].join('\n\n');

var prompt =
  'You are analyzing REAL government contract data retrieved live from USASpending.gov and Tavily web searches for Georgetown Defense Analytics (GDA).\n\n' +
  'CRITICAL RULES:\n' +
  '1. Tag every dollar figure with its source: [USASpending FY2025] | [Tavily: <URL>] | [ESTIMATED - no verified source]\n' +
  '2. If USASpending returned ZERO contracts for an agency, ALL spending figures MUST be tagged [ESTIMATED - no verified source found]\n' +
  '3. Never present training-data dollar amounts as facts without an [ESTIMATED] tag\n' +
  '4. USASpending figures = sum of top 50 keyword-matched contract awards, NOT total agency obligation\n' +
  '5. For Tavily figures, include the specific source URL in your tag\n\n' +
  '=== LIVE USASpending.gov CONTRACT DATA (FY2025) ===\n' + sections + '\n\n' +
  '=== WEB INTELLIGENCE (Tavily) ===\n\n' +
  'SEARCH: "TRADOC budget FY2025 FY2026 contract spending"\n' + extractTavily(tav1) + '\n\n' +
  'SEARCH: "SOCOM USSOCOM contract spending FY2025 site:usaspending.gov OR site:defense.gov"\n' + extractTavily(tav2) + '\n\n' +
  'SEARCH: "PEO STRI annual budget program office spending 2025 2026"\n' + extractTavily(tav3) + '\n\n' +
  '=== GDA OPERATING UNITS ===\n' +
  '* EIS (envision-is.com): XR, simulation, LVC, curriculum — serves PEO STRI, TRADOC, SOCOM\n' +
  '* PD Systems (pd-sys.net): C5ISR, logistics, AI/ML, enterprise IT — serves AFC, DLA, PEO Aviation\n' +
  '* Riverstone (rivsol.com): SIGINT, cyber, Zero Trust, DevSecOps — serves INSCOM, CYBERCOM, NSA\n\n' +
  '=== OUTPUT ===\n' +
  'Return JSON with "top_clients" array (all 7 agencies) and "generated_at".\n' +
  'Each agency object:\n' +
  '  agency, fy_budget (with source tag), data_source ("USASpending.gov FY2025"|"Tavily"|"Estimated"),\n' +
  '  top_contracts_sum_usd (integer from USASpending or null), gda_ou ("EIS"|"PD Systems"|"Riverstone"),\n' +
  '  gda_fit (1-10), gda_addressable (with source tag), key_programs (3-item array from verified data),\n' +
  '  eis_opportunities (text), confidence ("HIGH - verified USASpending data"|"MEDIUM - partial/web"|"LOW - estimated only")\n\n' +
  'Return ONLY valid JSON. No markdown. No text outside the JSON.';

var data_freshness = new Date().toISOString();

return [{ json: { data_freshness_timestamp: data_freshness, analysis_prompt: prompt } }];

const resp = $input.first().json;
const raw = (resp.content?.[0]?.text || resp.choices?.[0]?.message?.content || '').trim();
let cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
const start = cleaned.indexOf('{');
const end   = cleaned.lastIndexOf('}');
if (start === -1 || end === -1) {
  return [{ json: { error: 'No JSON found in Claude response', raw_snippet: raw.substring(0, 400), generated_at: new Date().toISOString() }}];
}
cleaned = cleaned.substring(start, end + 1);
try {
  const parsed = JSON.parse(cleaned);
  if (!parsed.generated_at) parsed.generated_at = new Date().toISOString();
  return [{ json: parsed }];
} catch(e) {
  return [{ json: { error: 'JSON parse error: ' + e.message, raw_snippet: raw.substring(0, 400), generated_at: new Date().toISOString() }}];
}

const deepDiveResp = $input.first().json;
const raw = (deepDiveResp.content?.[0]?.text || deepDiveResp.choices?.[0]?.message?.content || '').trim();
const priorData = $('Parse Response').first().json;
let agencyPrograms = {};
let cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
const start = cleaned.indexOf('{');
const end = cleaned.lastIndexOf('}');
if (start !== -1 && end !== -1) {
  cleaned = cleaned.substring(start, end + 1);
  try { const parsed = JSON.parse(cleaned); agencyPrograms = parsed.agency_programs || {}; }
  catch(e) { agencyPrograms = { parse_error: e.message, raw_snippet: raw.substring(0, 500) }; }
} else {
  agencyPrograms = { error: 'No JSON object found in deep dive response', raw_snippet: raw.substring(0, 500) };
}
return [{ json: { top_clients: priorData.top_clients || [], agency_programs: agencyPrograms, generated_at: priorData.generated_at || new Date().toISOString() }}];

const data = $input.first().json;
const raw = data.agency_programs || {};
function parseBudgetToUSD(s) {
  if (!s || typeof s !== 'string') return 0;
  const m = s.match(/\$([\d.]+)\s*(B|M|K)?/i);
  if (!m) return 0;
  const num = parseFloat(m[1]);
  const unit = (m[2] || 'M').toUpperCase();
  if (unit === 'B') return Math.round(num * 1e9);
  if (unit === 'M') return Math.round(num * 1e6);
  if (unit === 'K') return Math.round(num * 1e3);
  return Math.round(num);
}
const enrichedClients = (data.top_clients || []).map(client => ({ ...client, fy_budget_usd: parseBudgetToUSD(client.fy_budget), gda_addressable_usd: parseBudgetToUSD(client.gda_addressable) }));
if (raw.parse_error || raw.error) {
  return [{ json: { top_clients: enrichedClients, agency_programs: [], agency_programs_error: raw, generated_at: data.generated_at || new Date().toISOString() }}];
}
const agencyArray = Object.entries(raw).map(([agencyName, offices]) => {
  const commands = Object.entries(offices || {}).map(([commandName, commandData]) => ({ command: commandName, mission: (commandData && commandData.mission) || '', programs: (commandData && commandData.programs) || [] }));
  return { agency: agencyName, commands: commands };
});
return [{ json: { top_clients: enrichedClients, agency_programs: agencyArray, generated_at: data.generated_at || new Date().toISOString() }}];
